import io.grpc.stub.StreamObserver;
import io.grpc.*;
import java.io.InputStream;
import java.util.concurrent.atomic.AtomicLong;

public class FileUploadServiceImpl extends FileUploadServiceGrpc.FileUploadServiceImplBase {

    @Override
    public StreamObserver<UploadRequest> upload(StreamObserver<UploadResponse> responseObserver) {
        AtomicLong bytesUploaded = new AtomicLong(0);

        return new StreamObserver<UploadRequest>() {
            @Override
            public void onNext(UploadRequest request) {
                byte[] data = request.getData().toByteArray();
                // Process the received data
                bytesUploaded.addAndGet(data.length);
                System.out.println("Bytes uploaded: " + bytesUploaded.get());
            }

            @Override
            public void onError(Throwable t) {
                responseObserver.onError(t);
            }

            @Override
            public void onCompleted() {
                UploadResponse response = UploadResponse.newBuilder()
                        .setSuccess(true)
                        .setMessage("File upload completed successfully")
                        .setBytesReceived(bytesUploaded.get())
                        .build();
                responseObserver.onNext(response);
                responseObserver.onCompleted();
            }
        };
    }

    public static void main(String[] args) throws IOException {
        ServerBuilder<?> serverBuilder = ServerBuilder.forPort(50051);

        serverBuilder.addService(new FileUploadServiceImpl());
        Server server = serverBuilder.build().start();

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            FileUploadServer.stop();
            System.err.println("*** server shut down");
        }));

        FileUploadServer.blockUntilShutdown();
    }

    private static void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    private static void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static Server server;
}